<?php namespace App\Repositories\Transport;use App\Repositories\BaseRepository;use App\Models\Transport\TransportVehicle;use Illuminate\Database\Eloquent\Collection;class TransportVehicleRepository extends BaseRepository{    public function __construct(TransportVehicle $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByRegistrationNo(string $registrationNo): ?TransportVehicle    {        return $this->query()->where('registration_no', $registrationNo)->first();    }    public function findByType(string $type): Collection    {        return $this->findByField('type', $type);    }    public function getActiveVehicles(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getAvailableVehicles(): Collection    {        return $this->query()->where('is_active', true)->where('status', 'available')->get();    }    public function getUnderMaintenanceVehicles(): Collection    {        return $this->query()->where('status', 'maintenance')->get();    }    public function searchVehicles(string $keyword): Collection    {        return $this->query()->where('registration_no', 'like', "%{$keyword}%")->orWhere('model', 'like', "%{$keyword}%")->orWhere('make', 'like', "%{$keyword}%")->orWhere('chassis_no', 'like', "%{$keyword}%")->get();    }    public function getInsuranceExpiringSoon(int $days = 30): Collection    {        return $this->query()->where('insurance_expiry', '>=', now())->where('insurance_expiry', '<=', now()->addDays($days))->get();    }    public function getByCapacity(int $minCapacity): Collection    {        return $this->query()->where('capacity', '>=', $minCapacity)->get();    }    public function updateStatus(int $id, string $status): bool    {        return $this->update($id, ['status' => $status]);    }}